/// <https://drafts.csswg.org/cssom-view/#document-run-the-scroll-steps>
pub(crate) fn run_the_scroll_steps(&self, can_gc: CanGc) {
    // Step 1.
    // > Run the steps to dispatch pending scrollsnapchanging events for doc.
    // TODO(#7673): Implement scroll snapping

    // Fire scrollend events for targets that are no longer scrolling.
    // This happens before scroll events so that scrollend fires after scroll events in the same frame.
    rooted_vec!(let scrollend_list <- self.pending_scrollend_event_targets.take().into_iter());

    // Get the current scroll event targets to check which ones are still scrolling
    let scroll_targets = self.pending_scroll_event_targets.borrow();

    for scrollend_target in scrollend_list.iter() {
        // Check if this target is getting a new scroll event
        let is_scrolling = scroll_targets.iter().any(|scroll_target| {
            scroll_target == scrollend_target
        });

        // If not scrolling, fire scrollend event
        if !is_scrolling {
            if scrollend_target.downcast::<Document>().is_some() {
                // For Document, scrollend bubbles
                scrollend_target.fire_bubbling_event(Atom::from("scrollend"), can_gc);
            } else if scrollend_target.downcast::<Element>().is_some() {
                // For Element, scrollend does not bubble
                scrollend_target.fire_event(Atom::from("scrollend"), can_gc);
            }
        } else {
            // Target is still scrolling, re-queue it for scrollend
            self.pending_scrollend_event_targets.borrow_mut().push(scrollend_target.clone());
        }
    }

    // Step 2
    // > For each item target in doc's pending scroll event targets, in the order they
    // > were added to the list, run these substeps:
    // Step 3.
    // > Empty doc's pending scroll event targets.
    // Since the scroll event callback could trigger another scroll event, we are taking all of the
    // current scroll event to avoid borrow checking error.
    rooted_vec!(let notify_list <- self.pending_scroll_event_targets.take().into_iter());
    for target in notify_list.iter() {
        if target.downcast::<Document>().is_some() {
            // Step 2.1
            // > If target is a Document, fire an event named scroll that bubbles at target.
            target.fire_bubbling_event(Atom::from("scroll"), can_gc);
        } else if target.downcast::<Element>().is_some() {
