        }

        // Queue scrollend event for the next render cycle if scrolling stops
        self.pending_scrollend_event_targets.borrow_mut().push(target.clone());
    }

    // Step 4.
    // > Run the steps to dispatch pending scrollsnapchange events for doc.
    // TODO(#7673): Implement scroll snapping
